import socket

def check_port(ip, port, timeout=1):
    try:
        sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        sock.settimeout(timeout)
        result = sock.connect_ex((ip, port))
        sock.close()
        return result == 0
    except:
        return False

ports_to_check = [80, 443, 22, 3000, 8929, 8080, 8091, 8092, 2999, 5050, 5432, 6379, 27017]

for i in range(2, 15):
    ip = f"172.17.0.{i}"
    for port in ports_to_check:
        if check_port(ip, port, 0.5):
            print(f"{ip}:{port} OPEN")
EOF

